impl<S> FromRequestParts<S> for ExtractUserRow
where
    S: Send + Sync,
{
    type Rejection = String;

    #[tracing::instrument(err(Debug), skip_all)]
    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let identity_id = parts
            .extract::<ExtractSession>()
            .await?
            .0
            .identity
            .ok_or("No identity")?
            .id;
        let pool = parts
            .extract::<axum::Extension<SqlitePool>>()
            .await
            .map_err(|err| format!("{err:#?}"))?
            .0;
        let user = crate::database_calls::read_user_by_identity_id(&pool, &identity_id)
            .await
            .map_err(|err| format!("{err:#?}"))?;

        Ok(Self(user))
    }
}

impl<T, Ser> ReadUntracked for ArcOnceResource<T, Ser>
where
    T: 'static,
{
    type Value = ReadGuard<Option<T>, Plain<Option<T>>>;

    fn try_read_untracked(&self) -> Option<Self::Value> {
        if let Some(suspense_context) = use_context::<SuspenseContext>() {
            if self.value.read().or_poisoned().is_none() {
                let handle = suspense_context.task_id();
                let mut ready =
                    Box::pin(SpecialNonReactiveFuture::new(self.ready()));
                match ready.as_mut().now_or_never() {
                    Some(_) => drop(handle),
                    None => {
                        reactive_graph::spawn(async move {
                            ready.await;
                            drop(handle);
                        });
                    }
                }
                self.suspenses.write().or_poisoned().push(suspense_context);
            }
        }
        Plain::try_new(Arc::clone(&self.value)).map(ReadGuard::new)
    }
}

